-- Функции ДФМ (детально по положению). Ветка 4.1 — Управление методологии и организации процессов (узел 4.1)
WITH ins AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, v.code
  FROM (VALUES
    ('4.1','Разработка и актуализация ПВК по ПОД/ФТ, ЦПВК и программ их осуществления, а также иных внутренних документов Банка по вопросам ПОД/ФТ в части, касающейся деятельности Управления методологии и организации процессов','methodology'),
    ('4.1','Осуществление консультирования работников Банка по вопросам, находящимся в компетенции Управления методологии и организации процессов','communication'),
    ('4.1','Проведение обучения и проверки знаний работников Банка по ПОД/ФТ','operational'),
    ('4.1','Организация контроля реализации процедур идентификации в целях ПОД/ФТ в рамках функционала Управления методологии и организации процессов','control'),
    ('4.1','Обеспечение сопровождения надзорной деятельности по вопросам, отнесённым к компетенции Подразделения','control'),
    ('4.1','Подготовка и направление в Банк России уведомлений о специальном должностном лице (при назначении, в том числе временно, об освобождении, в том числе временно), ответственном за реализацию ПВК по ПОД/ФТ, и лице, временно осуществляющем его функции в Банке, а также об изменениях анкетных данных указанных лиц (указание Банка России от 25.12.2017 № 4662-У)','regulatory'),
    ('4.1','Получение информации от структурных подразделений в целях ежемесячного информирования руководителей Службы внутреннего аудита и Службы внутреннего контроля о выявленных фактах нарушения законодательства в сфере ПОД/ФТ работниками Банка','control'),
    ('4.1','Получение информации от структурных подразделений в целях подготовки ежеквартального отчёта о результатах реализации ПВК по ПОД/ФТ для курирующего заместителя Председателя Банка','control'),
    ('4.1','Получение информации от структурных подразделений в целях подготовки ежегодного отчёта о результатах реализации ПВК по ПОД/ФТ, ЦПВК, согласованного с курирующим заместителем Председателя Банка, рекомендуемых мерах по улучшению системы ПОД/ФТ, для Наблюдательного совета Банка','control'),
    ('4.1','Обеспечение своевременного направления курирующему заместителю Председателя Банка Отчёта ежеквартального','control'),
    ('4.1','Обеспечение своевременного направления Наблюдательному совету Банка Отчёта ежегодного, согласованного с курирующим заместителем Председателя Банка','control'),
    ('4.1','Обеспечение согласования ключевых показателей эффективности работников УФМ СЦ','operational')
  ) AS v(code, title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins.id, u.id, 'owner', 'polozhenie'
FROM ins JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = ins.source_section_code AND u.is_archived = false;